"""
MKT Echo Layer — Job chapters 15–18
Run: python3 scripts/zc-echo-job-15-18.py

Ch15: Eliphaz's second speech — born of woman, drinking wickedness (15:14-16) — John 3:6; Rom 3:23
      The wicked man's fearful life — no peace, waiting for darkness (15:20-23) — John 14:27; Heb 2:15
Ch16: Job's anguished appeal — his witness is in heaven (16:19) — Heb 7:25; 1 John 2:1
      Earth, do not cover my blood — the cry for vindication (16:18) — Heb 12:24
      My eye pours out tears to God on behalf of a man (16:21) — Heb 5:7; Rom 8:34
Ch17: Job despairs — my spirit is broken, my days are extinct (17:1) — 2 Cor 4:16; Rom 8:26
      Where then is my hope? — the question the resurrection answers (17:15) — 1 Pet 1:3
Ch18: Bildad on the fate of the wicked — light extinguished, roots dried up (18:5-6) — John 15:6; Rev 20:15
      The firstborn of death (18:13) — 1 Cor 15:26; Rev 20:14
      He is driven from light into darkness (18:18) — John 3:19; 12:46
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_echo(book):
    p = ROOT / 'data' / 'echoes' / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_echo(book, data):
    p = ROOT / 'data' / 'echoes' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_echo(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, entries in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = entries
            else:
                seen = {(e['type'], e['target']) for e in existing[ch][v]}
                for e in entries:
                    if (e['type'], e['target']) not in seen:
                        existing[ch][v].append(e)
                        seen.add((e['type'], e['target']))

ECHOES = {
  "15": {
    "14": [
      {"type": "allusion", "target": "John 3:6", "note": "What is man that he can be pure? Or he who is born of a woman, that he can be righteous? — Eliphaz's second-speech argument from human constitution: birth from a woman entails creaturely limitation and moral contamination. John 3:6: 'That which is born of the flesh is flesh, and that which is born of the Spirit is spirit.' Jesus uses the same birth-logic to establish the necessity of new birth: what is generated by flesh produces flesh; only the Spirit's act generates spiritual life. The gospel does not dispute Eliphaz's anthropology — human birth produces beings who cannot of themselves stand righteous before God — but answers it with the new birth that Eliphaz cannot imagine."}
    ],
    "16": [
      {"type": "allusion", "target": "Rom 3:23", "note": "How much less one who is abominable and corrupt, a man who drinks injustice like water! — Eliphaz's escalation from creaturely limitation to active moral depravity. Romans 3:23: 'for all have sinned and fall short of the glory of God.' Paul's universal statement and Eliphaz's rhetorical challenge share the same anthropological ground: no human being achieves the righteousness that standing before God requires. The difference is that Paul immediately continues: 'and are justified by his grace as a gift, through the redemption that is in Christ Jesus' (3:24). Eliphaz has the diagnosis; the gospel alone provides the remedy."}
    ],
    "20": [
      {"type": "allusion", "target": "Heb 2:15", "note": "The wicked man writhes in pain all his days — the sound of terror is in his ears, in prosperity the destroyer comes upon him. He does not believe he will return out of darkness, and he is marked for the sword. Hebrews 2:15 names this terror as the universal human condition under the power of death: Christ came to 'deliver all those who through fear of death were subject to lifelong slavery.' Eliphaz intends the terror-filled, darkness-haunted existence as a portrait of the wicked; but Hebrews suggests it describes the human condition in Adam — all are subject to the fear that makes life a form of slavery until liberation comes through Christ's conquest of death."}
    ],
    "23": [
      {"type": "allusion", "target": "John 14:27", "note": "He wanders for food — where is it? He knows that a day of darkness is ready at his hand. The description of the wicked man's fearful, food-seeking restlessness — a life without peace — is the shadow of what Christ offers. John 14:27: 'Peace I leave with you; my peace I give to you. Not as the world gives do I give to you. Let not your hearts be troubled, neither let them be afraid.' The restless dread Eliphaz assigns to the wicked is the universal condition the gospel addresses: the peace Christ gives does not merely reverse circumstances but transforms the orientation of the heart toward death, darkness, and the future."}
    ]
  },
  "16": {
    "18": [
      {"type": "allusion", "target": "Heb 12:24", "note": "O earth, cover not my blood, and let my cry find no resting place! — Job's appeal to the earth to preserve his blood as witness, refusing to allow his unjust suffering to be silently absorbed. Abel's blood cried out from the ground (Gen 4:10); Job demands the same ongoing witness. Hebrews 12:24 explicitly contrasts this with the blood of Christ: 'Jesus, the mediator of a new covenant, and to the sprinkled blood that speaks a better word than the blood of Abel.' Abel's blood cried for vengeance; Christ's blood speaks forgiveness. Job's blood-cry anticipates both: the demand for vindication that the gospel addresses not by silencing the cry but by the one who absorbed its verdict on behalf of those who deserve it."}
    ],
    "19": [
      {"type": "allusion", "target": "1 John 2:1", "note": "Even now, behold, my witness is in heaven, and he who testifies for me is on high — Job's affirmation that despite all appearances, a heavenly witness exists who holds his case. 1 John 2:1: 'if anyone does sin, we have an advocate with the Father, Jesus Christ the righteous.' Job's desperate postulate — a heavenly advocate — is the NT's confident declaration. The heavenly witness Job gropes toward in the darkness of undeserved suffering is identified in the NT as the glorified Christ interceding at the right hand of the Father. Job's faith-assertion against all evidence prefigures the believer's assurance grounded in the completed work of the one who was himself, like Job, accused by the adversary."}
    ],
    "21": [
      {"type": "allusion", "target": "Heb 5:7", "note": "That he would argue the case of a man with God, as a son of man does with his neighbor — Job's longing for a mediator who would plead his case before God with the intimacy a man uses with his friend. Hebrews 5:7: 'In the days of his flesh, Jesus offered up prayers and supplications, with loud crying and tears, to him who was able to save him from death, and he was heard because of his reverence.' Christ's Gethsemane prayer is the fulfillment of Job's longing: not a formal legal advocate but one who argues the case with tears, with the intimacy of a son addressing a father, and who was heard — not by being spared suffering but by being raised through it."},
      {"type": "allusion", "target": "Rom 8:34", "note": "The plea on behalf of a man — Job's longing for intercession that will not merely be heard by God but will argue with the force of personal identification with the one suffering. Romans 8:34: 'who is to condemn? Christ Jesus is the one who died — more than that, who was raised — who is at the right hand of God, who indeed is interceding for us.' Paul's intercession is grounded in Christ's completed work: he argues the case not from outside the human condition but from within it — as one who himself suffered unjustly, died, and was vindicated by resurrection. Job's longing is answered not by a neutral arbiter but by one who knows what it is to be in Job's position."}
    ]
  },
  "17": {
    "1": [
      {"type": "allusion", "target": "2 Cor 4:16", "note": "My spirit is broken; my days are extinct; the graveyard is ready for me. — Job's confession of utter exhaustion: the inner person shattered, life's remaining days numbered, death anticipated. 2 Corinthians 4:16: 'So we do not lose heart. Though our outer self is wasting away, our inner self is being renewed day by day.' Paul's apostolic experience directly parallels Job's description — the outer wasting away, the sense that the graveyard approaches — but Paul writes from the other side of the resurrection: the same suffering that destroys from without becomes the occasion for inner renewal. Job cannot yet see what Paul has been given to see."}
    ],
    "15": [
      {"type": "allusion", "target": "1 Pet 1:3", "note": "Where then is my hope? Who will see my hope? — Job's desolate question as he anticipates Sheol: if hope goes down with him to the dust, it cannot be real hope. 1 Peter 1:3: 'Blessed be the God and Father of our Lord Jesus Christ! According to his great mercy, he has caused us to be born again to a living hope through the resurrection of Jesus Christ from the dead.' The living hope Peter celebrates is specifically the answer to Job's question: it is hope that does not go down to the dust because it is grounded in a resurrection that goes through the dust and comes out the other side. Job's question is the darkness that precedes the dawn of resurrection hope."}
    ]
  },
  "18": {
    "5": [
      {"type": "allusion", "target": "John 15:6", "note": "Indeed, the light of the wicked is put out, and the flame of his fire does not shine — Bildad's portrait of the wicked man's extinction. John 15:6: 'If anyone does not abide in me he is thrown away like a branch and withers; and the branches are gathered, thrown into the fire, and burned.' Both texts use the extinguishing of light and fire as the image of the final condition of those cut off from God. The NT sharpens the typological edge: the light that is extinguished is not merely the lamp of earthly prosperity but the life that comes only from abiding in Christ, who is the light of the world (John 8:12). Without him, the flame goes out."}
    ],
    "13": [
      {"type": "allusion", "target": "1 Cor 15:26", "note": "It consumes the parts of his skin; the firstborn of death consumes his limbs. The firstborn of death — a personification of death's most destructive power — consumes the wicked man piece by piece. 1 Corinthians 15:26: 'The last enemy to be destroyed is death.' Paul's eschatological language takes Bildad's poetic figure and places it in the horizon of Christ's victory: death as the ultimate enemy, the firstborn of which Bildad speaks, has been defeated in principle in the resurrection and will be destroyed finally at the last day. What Bildad presents as the wicked man's fate becomes in the NT the enemy Christ absorbs and conquers — entering death's domain (the firstborn of death's territory) and emerging as the firstborn from the dead (Col 1:18)."},
      {"type": "allusion", "target": "Rev 20:14", "note": "The firstborn of death devours — the personification of death as an active destroyer, consuming the wicked. Revelation 20:14: 'Then Death and Hades were thrown into the lake of fire. This is the second death, the lake of fire.' The firstborn of death that Bildad uses as a figure for extreme destruction is itself destroyed in the Revelation's final judgment: Death personified is thrown into the lake of fire. The creature that Bildad's poetics makes fearsome is undone by the one who holds the keys of death and Hades (Rev 1:18) — the risen Christ who conquered the firstborn of death by passing through death and returning."}
    ],
    "18": [
      {"type": "allusion", "target": "John 3:19", "note": "He is thrust from light into darkness, and driven out of the world — Bildad's picture of the wicked man's final expulsion from light and life into darkness. John 3:19: 'And this is the judgment: the light has come into the world, and people loved the darkness rather than the light because their works were evil.' Both texts use the movement from light to darkness as the structure of judgment. Bildad describes the wicked man's end; John describes the mechanism of self-judgment: the light came into the world in Christ, and those who refused it chose darkness. The thrust from light that Bildad presents as an external punishment is revealed in John as the logical consequence of a prior choice."}
    ]
  }
}

def main():
    e = load_echo('job')
    merge_echo(e, ECHOES)
    save_echo('job', e)
    count = sum(len(v) for v in ECHOES.values())
    print(f'job echo: wrote entries for {count} chapters across ch 15-18')

if __name__ == '__main__':
    main()
